+  model: string;
+  created_at: string;
+  message: {
+    role: "assistant";
+    content: string;
+    thinking?: string;
+    reasoning?: string;
+    tool_calls?: OllamaToolCall[];
+  };
+  done: boolean;
+  done_reason?: string;
+  total_duration?: number;
+  load_duration?: number;
+  prompt_eval_count?: number;
+  prompt_eval_duration?: number;
+  eval_count?: number;
+  eval_duration?: number;
