+  return buildStreamAssistantMessage({
+    model: modelInfo,
+    content,
+    stopReason: toolCalls && toolCalls.length > 0 ? "toolUse" : "stop",
+    usage: buildUsageWithNoCost({
+      input: response.prompt_eval_count ?? 0,
+      output: response.eval_count ?? 0,
+    }),
+  });
