+function resolveOllamaChatUrl(baseUrl: string): string {
+  const trimmed = baseUrl.trim().replace(/\/+$/, "");
+  const normalizedBase = trimmed.replace(/\/v1$/i, "");
+  return `${normalizedBase || OLLAMA_NATIVE_BASE_URL}/api/chat`;
+}
